export function createBasicUI({
  mountEl,
  rpcUrl,
  chainId,
  defaultAbi = null,
  defaultContract = "",
  defaultFunction = "",
} = {}) {
  const root = typeof mountEl === "string" ? document.querySelector(mountEl) : mountEl;
  if (!root) throw new Error("mountEl not found.");

  const app = new EthersDApp({ rpcUrl, chainId });
  const state = {
    abi: defaultAbi,
    contract: defaultContract,
    fn: defaultFunction,
  };

  root.innerHTML = `
    <div style="font-family: ui-sans-serif, system-ui; max-width: 980px;">
      <div style="display:flex; gap:12px; align-items:center; flex-wrap:wrap;">
        <button data-id="connect">Connect Wallet</button>
        <div data-id="status" style="padding:6px 10px; border:1px solid #ddd; border-radius:6px;">Not connected</div>
      </div>

      <h3>Contract</h3>
      <div style="display:grid; grid-template-columns: 1fr 1fr; gap:12px;">
        <label>Contract Address<br/><input data-id="contract" style="width:100%;" placeholder="0x..." value="${escapeHtml(
          state.contract || ""
        )}"/></label>
        <label>Function Name<br/><input data-id="fn" style="width:100%;" placeholder="transfer" value="${escapeHtml(
          state.fn || ""
        )}"/></label>
      </div>

      <h3>ABI</h3>
      <textarea data-id="abi" style="width:100%; height:160px;" placeholder='Paste ABI JSON here'>${
        state.abi ? escapeHtml(JSON.stringify(state.abi, null, 2)) : ""
      }</textarea>

      <h3>Args (JSON array)</h3>
      <textarea data-id="args" style="width:100%; height:90px;" placeholder='["0xabc...", "1000000000000000000"]'></textarea>

      <h3>Transaction Options</h3>
      <div style="display:grid; grid-template-columns: 1fr 1fr 1fr; gap:12px;">
        <label>Value (ETH / gwei / wei or hex)<br/><input data-id="value" style="width:100%;" placeholder="0.01 eth"/></label>
        <label>Gas Limit<br/><input data-id="gasLimit" style="width:100%;" placeholder="210000"/></label>
        <label>Confirmations<br/><input data-id="conf" style="width:100%;" placeholder="1" value="1"/></label>
      </div>

      <details style="margin-top:10px;">
        <summary>Advanced Overrides (JSON)</summary>
        <textarea data-id="overrides" style="width:100%; height:110px;" placeholder='{"maxFeePerGas":"30 gwei","maxPriorityFeePerGas":"1.5 gwei"}'></textarea>
      </details>

      <div style="display:flex; gap:10px; align-items:center; flex-wrap:wrap; margin-top:12px;">
        <button data-id="read">Read (call)</button>
        <button data-id="send">Send (transaction)</button>
        <button data-id="build">Build Tx (preview)</button>
        <button data-id="estimate">Estimate Gas</button>
      </div>

      <h3>Output</h3>
      <pre data-id="out" style="background:#0b1020; color:#e7ecff; padding:12px; border-radius:8px; overflow:auto; min-height:140px;"></pre>
    </div>
  `;

  const $ = (sel) => root.querySelector(sel);

  const el = {
    connect: $('[data-id="connect"]'),
    status: $('[data-id="status"]'),
    contract: $('[data-id="contract"]'),
    fn: $('[data-id="fn"]'),
    abi: $('[data-id="abi"]'),
    args: $('[data-id="args"]'),
    value: $('[data-id="value"]'),
    gasLimit: $('[data-id="gasLimit"]'),
    conf: $('[data-id="conf"]'),
    overrides: $('[data-id="overrides"]'),
    read: $('[data-id="read"]'),
    send: $('[data-id="send"]'),
    build: $('[data-id="build"]'),
    estimate: $('[data-id="estimate"]'),
    out: $('[data-id="out"]'),
  };

  function setOut(v) {
    el.out.textContent =
      typeof v === "string"
        ? v
        : JSON.stringify(
            v,
            (_, val) => (typeof val === "bigint" ? val.toString() : val),
            2
          );
  }

  function getAbi() {
    const s = el.abi.value.trim();
    if (!s) throw new Error("ABI is required.");
    const abi = JSON.parse(s);
    if (!Array.isArray(abi)) throw new Error("ABI must be a JSON array.");
    return abi;
  }

  function getArgsArray() {
    const s = el.args.value.trim();
    if (!s) return [];
    const parsed = JSON.parse(s);
    if (!Array.isArray(parsed)) throw new Error("Args must be a JSON array.");
    return parsed;
  }

  function getOverridesObject() {
    const base = {};
    const gasLimit = el.gasLimit.value.trim();
    if (gasLimit) base.gasLimit = gasLimit;

    const adv = el.overrides.value.trim();
    const advObj = adv ? JSON.parse(adv) : {};
    if (advObj && typeof advObj !== "object") throw new Error("Overrides JSON must be an object.");

    return { ...advObj, ...base };
  }

  async function refreshStatus() {
    const addr = app.address;
    if (addr) el.status.textContent = `Connected: ${addr}`;
    else el.status.textContent = "Not connected";
  }

  el.connect.addEventListener("click", async () => {
    try {
      await app.init();
      const addr = await app.connectWallet();
      setOut({ connected: addr });
      await refreshStatus();
    } catch (e) {
      setOut({ error: e?.message || String(e) });
    }
  });

  app.on("accountsChanged", refreshStatus);
  app.on("disconnect", refreshStatus);

  el.read.addEventListener("click", async () => {
    try {
      await app.init();
      const abi = getAbi();
      const contractAddress = el.contract.value.trim();
      const functionName = el.fn.value.trim();
      const rawArgs = getArgsArray();
      const args = app.parseUserArgs({ abi, functionName, rawArgs });

      const res = await app.callContract({
        contractAddress,
        abi,
        functionName,
        args,
        withSigner: false,
      });

      setOut(res);
    } catch (e) {
      setOut({ error: e?.message || String(e) });
    }
  });

  el.build.addEventListener("click", async () => {
    try {
      await app.init();
      const abi = getAbi();
      const contractAddress = el.contract.value.trim();
      const functionName = el.fn.value.trim();
      const rawArgs = getArgsArray();
      const args = app.parseUserArgs({ abi, functionName, rawArgs });

      const rawValue = el.value.value.trim();
      const overrides = app.parseOverridesFromUserInput(getOverridesObject());

      const tx = await app.buildContractTx({
        contractAddress,
        abi,
        functionName,
        args,
        value: rawValue || overrides.value,
        overrides: rawValue ? overrides : overrides,
      });

      setOut(tx);
    } catch (e) {
      setOut({ error: e?.message || String(e) });
    }
  });

  el.estimate.addEventListener("click", async () => {
    try {
      await app.init();
      const abi = getAbi();
      const contractAddress = el.contract.value.trim();
      const functionName = el.fn.value.trim();
      const rawArgs = getArgsArray();
      const args = app.parseUserArgs({ abi, functionName, rawArgs });
      const rawValue = el.value.value.trim();
      const overrides = app.parseOverridesFromUserInput(getOverridesObject());

      const tx = await app.buildContractTx({
        contractAddress,
        abi,
        functionName,
        args,
        value: rawValue || overrides.value,
        overrides: rawValue ? overrides : overrides,
      });

      const gas = await app.estimateGas(tx);
      setOut({ gas: gas.toString(), tx });
    } catch (e) {
      setOut({ error: e?.message || String(e) });
    }
  });

  el.send.addEventListener("click", async () => {
    try {
      await app.init();
      await app.connectWallet();

      const abi = getAbi();
      const contractAddress = el.contract.value.trim();
      const functionName = el.fn.value.trim();
      const rawArgs = getArgsArray();
      const rawValue = el.value.value.trim();
      const confirmations = Number(el.conf.value.trim() || "1");
      const rawOverrides = getOverridesObject();

      const result = await app.buildAndSendContractTxFromUserInput({
        contractAddress,
        abi,
        functionName,
        rawArgs,
        rawValue,
        rawOverrides,
        confirmations,
      });

      setOut(result);
      await refreshStatus();
    } catch (e) {
      setOut({ error: e?.message || String(e) });
    }
  });

  (async () => {
    try {
      await app.init();
      await refreshStatus();
    } catch (_) {}
  })();

  return { app, root };
}

function escapeHtml(s) {
  return String(s)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}